Edit platform/plugin-sdk/src/fetch.ts. Add overloaded signatures for fetchJSON:

```typescript
export async function fetchJSON<T extends z.ZodType>(url: string, init: FetchFromPageOptions | undefined, schema: T): Promise<z.infer<T>>;
export async function fetchJSON<T>(url: string, init?: FetchFromPageOptions): Promise<T>;
export async function fetchJSON(url: string, init?: FetchFromPageOptions, schema?: z.ZodType): Promise<unknown> {
  const response = await fetchFromPage(url, init);
  const data: unknown = await response.json();
  if (schema) {
    const result = schema.safeParse(data);
    if (!result.success) {
      throw ToolError.validation(`Invalid response from ${url}: ${result.error.message}`);
    }
    return result.data;
  }
  return data;
}
```

Do the same for postJSON. Import z from 'zod'.

